var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"에퉤퉤…… 모래 폭풍이 강해지고 있어요.","JPN":"ぺっぺっ、砂嵐がさらに強力になってきましたね。","ENG":"Pft. Pft pft... The sandstorm is getting stronger.","TWN":"糟糕……沙塵暴越來越強了。 "},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"역시 저 고래 같은 침식체가 모래 폭풍이 강해진 원인인 건가…….","JPN":"ひょっとして、あのクジラのような侵食体が原因だったり……？","ENG":"So is that whale-like C.O. the reason this sandstorm is getting stronger...?","TWN":"果然是那隻像鯨魚一樣的侵蝕體導致沙塵暴變強的吧……"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"저 고래만 토벌한다면 일이 더 수월해진다는 소리로군.","JPN":"あのクジラを倒すことができれば、探索が容易になるだろうな。","ENG":"That means that by killing it, our work here will become easier.","TWN":"意思就是，如果能消滅掉那隻鯨魚，情況會好一點吧。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"무슨 수로요? 몸으로 부딪쳐 봤자 생채기도 안 날 것 같은데요?","JPN":"でもどうやってですか？　こっちの攻撃が通じる相手とはとても思えないんですけど……","ENG":"But how? I don't think we'll be able to even put a scratch in that thing.","TWN":"該怎麼辦？就算是肉搏戰，它應該也不痛不癢吧？"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그러면 여기서 가만히 폭풍에 휩쓸려 죽어야 한다는 건가?","JPN":"では、このまま嵐に飲み込まれて死ねというのか？","ENG":"Then, are you saying you'd rather stay here and let the storm kill you?","TWN":"難道要就這樣靜待沙塵暴將我們吞噬嗎？ "},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L14_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"도망쳐야죠. 지금 저렇게 큰 녀석을 어떻게 상대해요?","JPN":"逃げるべきです。あんなデカいやつと戦うなんて、無茶です。","ENG":"We must run away. We're ill-equipped to deal with something that huge.","TWN":"當然跑。問題是現在要怎麼對付那個大塊頭？"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그럼 우리가 도망가는 동안 저 녀석은 우리를 가만히 지켜만 보고 있을 거고?","JPN":"私たちが逃げるまで、奴が大人しく待ってくれるとでも思うか？","ENG":"And you think that thing will just stand back and watch as we run away from it?","TWN":"那個大塊頭會坐視我們逃掉嗎？"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"누군가는 공격을 막아줘야지.","JPN":"どちらかは奴を止めておかなければならん。","ENG":"Someone has to block its attacks.","TWN":"當然必須要有個人來抵擋攻擊。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그리고 그건 몸이 더 튼튼한 내 역할이다.","JPN":"もちろん、身体が頑丈な私がその役割を担うぞ。","ENG":"And that'll be my job as I'm stronger than you.","TWN":"而這個角色，由我這個身強體壯的來擔任。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아유! 목숨이 더 소중하다면서요! 이 거짓말쟁이!","JPN":"もう！　命が優先だって言ったじゃないですか！　嘘つき！","ENG":"Ugh! What about your talk about life being more precious?! Liar!","TWN":"可惡！你不是說過生命更寶貴嗎！你這個騙子！"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"걱정하지 마라.","JPN":"大丈夫だ。","ENG":"Don't worry.","TWN":"不用擔心。 "},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"이 무장은 단순한 검이 아니야. 이건…….","JPN":"この装備は単なる剣ではない。これは……","ENG":"This armament is no ordinary sword. This is...","TWN":"這可不是把普通的劍，這是……"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"음? 저 녀석, 입에서 뭔가가…….","JPN":"うん？　奴の口から何かが……","ENG":"Hmm? Something coming from its mouth...","TWN":"嗯？那傢伙的嘴巴裡好像……"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"엣…… 잠깐…….","JPN":"えっ……ちょっと……","ENG":"Huh...? Hold it...","TWN":"呃……等等……"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"우아악! 멀리서부터 우리를 공격하고 있어요!","JPN":"うわあっ！　遠距離から攻撃してきました！","ENG":"WHOAAA! It's trying to attack us from afar!","TWN":"糟糕！它從遠處攻擊我們！"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"입에서 빔을 쏘고 있다고요! 저거!","JPN":"口からビームを出しています！　あいつ！","ENG":"It's shooting a laser beam from its mouth!!","TWN":"嘴巴還會射出光束！"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_BOOM"},{"id":"L35_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"젠장. 생긴 건 몸으로 밀어붙이게 생겨서는.","JPN":"くっ、いかにも突撃してくるような見た目なんだが。","ENG":"Dammit. This is not expected.","TWN":"該死，還以為只是塊頭大而已！"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"이대로 가면 도망이고 뭐고 바싹 익어버릴 거예요! ","JPN":"このままでは逃げる前に、焼け焦げにされてしまいます！ ","ENG":"At this rate, we'll be burnt to a crisp even if we try to run away!","TWN":"再這樣下去，不要說逃跑，我們會直接被烤熟吧！"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"원거리에서 공격하면서 우리에게 접근하고 있다!","JPN":"遠距離から攻撃を飛ばしつつ、こちらに向かってきている！","ENG":"It's attacking from a distance while approaching us!","TWN":"那傢伙進行遠距離攻擊的同時也不斷向我們靠近！"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BOOM"},{"id":"L42_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"으, 으아아?! 위험해요!","JPN":"う、うわあっ！　危険です！","ENG":"U-uaaah?! Watch out!","TWN":"還不快使用你的武器！"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그 무장인지 뭔지 얼른 써보라고요!","JPN":"その装備はまだ使う気ないんですか！？","ENG":"Use that armament or whatever it's called already!"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"큭! 알고 있어!","JPN":"くっ！　わかっている！","ENG":"Kgh! I'm trying!","TWN":"唔！好！"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"무기를 시동하고 힘을 개방하겠다!","JPN":"武器を始動し、力を解放する！","ENG":"I'll activate my weapon and unleash the power!","TWN":"啟動武器，釋放力量！"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L1_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"……!","JPN":"……！","ENG":"...!","TWN":"……！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"여긴……?","JPN":"ここは……？","ENG":"Where am I...?","TWN":"這裡是……？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"결국 이번에도 혼자 남게 되겠네요.","JPN":"結局、今回もまた一人になりますね。","ENG":"Seems that you're all alone again.","TWN":"看來這次也只剩下自己一個。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIEST_ORDER_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"MAN_NPC_GEASS_QM","text":{"KOREA":"당연한 수순이지.","JPN":"当然なまでだ。","ENG":"A natural outcome.","TWN":"這是理所當然的。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_GEASS_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"MAN_NPC_GEASS_QM","text":{"KOREA":"이 자는 항상 고독할 수밖에 없는 운명이니까.","JPN":"彼女は一人になるしかない運命なんだから。","ENG":"This one is fated to always be alone.","TWN":"這個人註定會永遠孤獨。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_GEASS_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"그렇네요. 지금도, 결국 홀로 남을 수밖에 없는 상황에 처해있군요.","JPN":"そうですね。今だって、結局は一人になろうとしています。","ENG":"Yes. Even now, the situation forces her to be alone.","TWN":"沒錯，甚至現在，也只能獨自一人。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIEST_ORDER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"이대로라면, 저 아이도 자기 손으로 죽이겠어요.","JPN":"このままでは、あの子まで殺めてしまいますね。","ENG":"At this rate, that child will die in her own hands.","TWN":"照這樣下去，那個孩子也會被她親手殺掉的。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIEST_ORDER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MAN_NPC_GEASS_QM","text":{"KOREA":"태양에 가까이 다가갈수록 몸이 타버리는 건 거스를 수 없으니까.\xA0","JPN":"太陽に近づけば、身体が燃え尽きてしまうのは避けられないことだ。\xA0","ENG":"For anyone who gets too close to the sun will eventually burn.\xA0","TWN":"越靠近太陽，身體被灼燒得就越厲害，這是無法避免的。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_GEASS_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":" 혼자 남을 수밖에 없는 운명? 그게 대체 무슨 소리지?","JPN":" 一人になるしかない運命だと？　いったい何を言っているんだ？","ENG":"Fated to be alone? What does that even mean?","TWN":"註定要獨自一人？那到底是什麼意思？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"이런, 아무래도 직접 확인하는 게 낫겠네요.","JPN":"これは、どうやら直接見てもらうしかなさそうですね。","ENG":"Oh. I think it would be best for you to find out for yourself.","TWN":"這個，就由你自己來確認比較好。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIEST_ORDER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"당신 곁에 동료가 있어선 안 되는 이유를.","JPN":"あなたのそばに仲間がいてはいけない理由を。","ENG":"Why you shouldn't have anyone by your side.","TWN":"你身邊不該有同伴的理由。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIEST_ORDER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"윽…… 아디트야…… 님? 어째서……?","JPN":"くっ……アーディティヤ様……？　どうして……？","ENG":"Ngh... Miss... Aditya? Why...?","TWN":"唔……阿迪亞……？為什麼……？"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"아샤! 도, 도대체 어떻게 된 거지?","JPN":"アーシャ！　い、いったい、何がどうなっている？","ENG":"Asha! W-what happened to you?","TWN":"阿莎！這，這到底是怎麼回事？"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"온몸이 상처투성이잖아!","JPN":"傷だらけじゃないか！","ENG":"You're injured everywhere!","TWN":"你渾身都是傷！"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"갑자기…… 아디트야 님의 몸에서 빛이 터져 나와서……. ","JPN":"突然……アーディティヤ様の身体が光り出して…… ","ENG":"A sudden light... burst out from your body, and...","TWN":"突然……從你身上發出光……"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"사방이…… 너무 뜨거워요…….","JPN":"周囲が……すごく熱くなって……","ENG":"it's burning... everywhere...","TWN":"周圍……好燙……"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"빛이…… 터져 나왔다고? 내가 널 이렇게…….\xA0","JPN":"光り……出した？　な、ならその傷は……","ENG":"A light... burst out? I did this...?\xA0","TWN":"有光……發出來？是我把你弄成這樣的……？"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"아니야…… 그럴 리가 없어…… 나는 분명…….\xA0","JPN":"いや……そんなはずは……私は確か……\xA0","ENG":"No... That can't be true... I was...\xA0","TWN":"不……不可能……我明明……"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"도망…… 치세요. 아디트야 님…….","JPN":"逃げて……ください。アーディティヤ様……","ENG":"R... un, Miss Aditya...","TWN":"快……逃。阿迪亞……"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"사람의 목숨은…… 소중하다면서요…….\xA0","JPN":"人の命は……大切だって言ってたじゃないですか……\xA0","ENG":"Life is important... remember...?\xA0","TWN":"性命……要緊……"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"아니야…… 아니야…….","JPN":"違う……違う……","ENG":"No... No...","TWN":"不…… 不是的……"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_45"},{"id":"L50_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"뜨거워…….","JPN":"熱い……","ENG":"It's burning...","TWN":"好燙……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":{"char_id":"PRIEST_ORDER_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE_02"},{"id":"L1_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"너…… 왜 우리를…….","JPN":"あなた……どうして私たちを……","ENG":"Why did you...","TWN":"你…為什麼要對我們……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":{"char_id":"PRIEST_ORDER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"나, 나는…….","JPN":"わ、私は……","ENG":"I-I...","TWN":"我，我……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":{"char_id":"PRIEST_ORDER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MAN_NPC_GEASS_QM","text":{"KOREA":"이름도 없이 떠돌던 걸 받아줬더니, 이런 식으로 보답하는군.","JPN":"名もない放浪娘を拾ってやったはいいものの、こんなふうに報いられるとはな。","ENG":"We took you in, who wandered around without name, and this is how you repay us.","TWN":"你一個四處流浪，連名字都沒有，我們好心接納你，結果你是這樣報答我們的嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MAN_NPC_GEASS_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MAN_NPC_GEASS_QM","text":{"KOREA":"너한테서 나온 그 빛은 뭐지? 괴물 같은 년…….","JPN":"お前が発したその光は何だ？　怪物め……","ENG":"What was that light that came out of you? You're a monster...","TWN":"你身上發出的光是怎麼回事？你這個怪物……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MAN_NPC_GEASS_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"아, 아니야. 나는 저 괴물들을 없애고 싶어서…….","JPN":"ち、違う。私は化け物を倒すために……","ENG":"N-no, I'm not. I just wanted to get rid of those monsters, and...","TWN":"不，不是的。我是想消滅那些怪物……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"분명 정신을 집중했는데…… 미, 미안해.","JPN":"集中していたはずなのだが……す、すまない。","ENG":"I was concentrating my mind... I-I’m so sorry.","TWN":"我明明有集中精神……對，對不起。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"제, 제발 눈 좀 떠봐!","JPN":"た、頼む……目を覚ましてくれ！","ENG":"P-please, open your eyes!","TWN":"求求你們，快睜開眼睛！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MAN_NPC_GEASS_QM","text":{"KOREA":"가까이 다가오지 마!","JPN":"こっちに来るな！","ENG":"Don't come any closer!","TWN":"不要靠近我！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MAN_NPC_GEASS_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MAN_NPC_GEASS_QM","text":{"KOREA":"그냥 꺼지라고!! ","JPN":"どっかに消えてしまえ！！ ","ENG":"Get lost!!","TWN":"給我滾！！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MAN_NPC_GEASS_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L16_1","type":"dialog","speaker":"MAN_NPC_GEASS_QM","text":{"KOREA":"지금은 괴물 새끼들보다 이상한 힘을 쓰는 네가 더 무서우니까.","JPN":"化け物なんかより、変な力を使うお前の方が怖いんだよ。","ENG":"Because we're more scared of you with your strange powers than those monsters right now.","TWN":"比起那些怪物，你的力量更令人害怕。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MAN_NPC_GEASS_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"아니야. 아니야…….","JPN":"違う……違う……","ENG":"No... No...","TWN":"不是的，不是的……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"난 아샤를…… 지켜야 해…….","JPN":"私はアーシャを……守るんだ……","ENG":"I must protect... Asha...","TWN":"我必須……保護阿莎……"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L23_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"절대로 이 아이에게 다가올 수 없을 거다.","JPN":"絶対に、この子には近づけさせない。","ENG":"I won't let you get close to her.","TWN":"我絕不會讓你靠近她。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};